                    <h2 id="authentication-POSTapi-auth-passkeys-authenticate">Authenticate with Passkey.</h2>

<p>
</p>

<p>Verifies the passkey challenge and logs the user in.</p>

<span id="example-requests-POSTapi-auth-passkeys-authenticate">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/auth/passkeys/authenticate" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"id\": \"architecto\",
    \"rawId\": \"architecto\",
    \"response\": {
        \"authenticatorData\": \"architecto\",
        \"clientDataJSON\": \"architecto\",
        \"signature\": \"architecto\"
    },
    \"type\": \"architecto\",
    \"clientExtensionResults\": [],
    \"remember\": true
