                    <h2 id="member-profiles-POSTapi-member-profiles">Create/Update current user profile</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Creates a new profile for the authenticated user if one doesn't exist, or updates the existing one.
This ensures the user has a linked profile record with necessary details like county and contact info.</p>

<span id="example-requests-POSTapi-member-profiles">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/member-profiles" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"county_id\": 47,
    \"first_name\": \"John\",
    \"last_name\": \"Doe\",
    \"phone\": \"+254712345678\",
    \"gender\": \"male\",
    \"date_of_birth\": \"1990-01-15\",
    \"occupation\": \"Software Developer\",
    \"membership_type\": \"free\",
    \"emergency_contact_name\": \"Jane Doe\",
    \"emergency_contact_phone\": \"+254798765432\",
    \"terms_accepted\": true,
    \"marketing_consent\": false,
    \"interests\": [
        \"technology\",
        \"community\"
    ],
    \"bio\": \"Enthusiastic learner.\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/member-profiles"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "county_id": 47,
    "first_name": "John",
    "last_name": "Doe",
    "phone": "+254712345678",
    "gender": "male",
    "date_of_birth": "1990-01-15",
    "occupation": "Software Developer",
    "membership_type": "free",
    "emergency_contact_name": "Jane Doe",
    "emergency_contact_phone": "+254798765432",
    "terms_accepted": true,
    "marketing_consent": false,
    "interests": [
        "technology",
        "community"
    ],
    "bio": "Enthusiastic learner."
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

