                    <h2 id="member-profiles-POSTapi-member-profiles-profile-picture">Upload profile picture</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Uploads and updates the authenticated user's profile picture.
Replaces any existing picture.</p>

<span id="example-requests-POSTapi-member-profiles-profile-picture">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/member-profiles/profile-picture" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: multipart/form-data" \
    --header "Accept: application/json" \
    --form "profile_picture=@C:\Users\pasca\AppData\Local\Temp\php25F1.tmp" </code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/member-profiles/profile-picture"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "multipart/form-data",
    "Accept": "application/json",
};

const body = new FormData();
body.append('profile_picture', document.querySelector('input[name="profile_picture"]').files[0]);

fetch(url, {
    method: "POST",
    headers,
    body,
}).then(response =&gt; response.json());</code></pre></div>

</span>

<span id="example-responses-POSTapi-member-profiles-profile-picture">
