                    <h2 id="data-retention-management-PUTapi-admin-retention-settings--retention_id-">Update Retention Policy</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Modifies the parameters of an existing data retention policy.
Allows administrators to change the retention period (in days), toggle automatic deletion, or update the policy description.
All changes are audit-logged.</p>

<span id="example-requests-PUTapi-admin-retention-settings--retention_id-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request PUT \
    "http://localhost:8000/api/admin/retention-settings/1" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"retention_days\": 90,
    \"retention_minutes\": 10,
    \"auto_delete\": true,
    \"description\": \"User account data retention\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/admin/retention-settings/1"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "retention_days": 90,
    "retention_minutes": 10,
    "auto_delete": true,
    "description": "User account data retention"
};

fetch(url, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

