                    <h2 id="data-retention-management-POSTapi-admin-schedulers-update">Configure Cleanup Schedule</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Configures the timing and frequency of automated cleanup commands.
Allows administrators to determine exactly when system maintenance tasks (like purging old data) run to minimize impact on active users.</p>

<span id="example-requests-POSTapi-admin-schedulers-update">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/admin/schedulers/update" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"command_name\": \"media:cleanup\",
    \"run_time\": \"03:00\",
    \"frequency\": \"daily\",
    \"enabled\": true
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/admin/schedulers/update"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "command_name": "media:cleanup",
    "run_time": "03:00",
    "frequency": "daily",
    "enabled": true
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

