                    <h2 id="admin-donation-campaigns-POSTapi-admin-donation-campaigns">Store New Campaign</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Create a new donation campaign with optional hero image.</p>

<span id="example-requests-POSTapi-admin-donation-campaigns">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/admin/donation-campaigns" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"title\": \"Emergency Relief Fund\",
    \"description\": \"Help us support affected communities\",
    \"short_description\": \"Relief campaign\",
    \"goal_amount\": 1000000,
    \"minimum_amount\": 100,
    \"currency\": \"KES\",
    \"featured_media_id\": 10,
    \"gallery_media_ids\": [
        16
    ],
    \"county_id\": 1,
    \"starts_at\": \"2025-01-01\",
    \"ends_at\": \"2025-01-31\",
    \"status\": \"draft\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/admin/donation-campaigns"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "title": "Emergency Relief Fund",
    "description": "Help us support affected communities",
