                    <h2 id="admin-event-attendance-POSTapi-admin-events--event_id--attendance-scan">Verify/Check-in QR Token</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Validates a ticket QR token and marks the attendee as checked in.
Supports both free RSVPs and paid tickets.</p>

<span id="example-requests-POSTapi-admin-events--event_id--attendance-scan">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/admin/events/1/attendance/scan" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"token\": \"TKT-abc123xyz\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/admin/events/1/attendance/scan"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "token": "TKT-abc123xyz"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

