    "sort_by": "starts_at",
    "sort_dir": "desc",
    "upcoming": "1",
    "type": "in_person",
    "timeframe": "upcoming",
    "per_page": "15",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

fetch(url, {
    method: "GET",
