};

let body = {
    "title": "Tech Conference 2025",
    "description": "Join us for a day of tech talks and networking.",
    "category_id": 1,
    "county_id": 35,
    "status": "draft",
    "starts_at": "2025-06-15 09:00:00",
    "ends_at": "2025-06-15 17:00:00",
    "registration_deadline": "2025-06-10 23:59:59",
    "venue": "Nairobi Convention Centre",
    "is_online": false,
    "online_link": "https:\/\/zoom.us\/j\/123456789",
    "capacity": 100,
    "waitlist_enabled": false,
    "image_path": "events\/tech-conf-2025.jpg",
    "featured_media_id": 10,
    "gallery_media_ids": [
        16
    ],
    "featured": false,
    "featured_until": "2025-06-01 00:00:00",
    "price": 500,
    "currency": "KES",
    "tag_ids": [
        16
    ],
    "tickets": [
        {
            "name": "General Admission",
            "price": 500,
            "quantity": 50
        }
    ],
    "speakers": [
        {
            "name": "John Doe",
            "designation": "CTO",
            "company": "Tech Corp"
        }
    ],
    "promo_codes": [
        {
            "code": "khwaykcmyuwpwlvq",
            "discount_type": "percentage",
            "discount_value": 22,
            "usage_limit": 30,
            "ticket_id": 16,
            "is_active": false
        }
    ]
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

