<span id="example-requests-PUTapi-admin-events--id-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request PUT \
    "http://localhost:8000/api/admin/events/1" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"title\": \"Updated Tech Conference 2025\",
    \"description\": \"Updated event description.\",
    \"category_id\": 1,
    \"county_id\": 35,
    \"starts_at\": \"2025-06-16 09:00:00\",
    \"ends_at\": \"2025-06-16 17:00:00\",
    \"registration_deadline\": \"2025-06-11 23:59:59\",
    \"venue\": \"Updated Venue Location\",
    \"is_online\": false,
    \"capacity\": 150,
    \"waitlist_enabled\": false,
    \"image_path\": \"events\\/updated-image.jpg\",
    \"featured_media_id\": 10,
    \"gallery_media_ids\": [
        16
    ],
    \"featured\": false,
    \"price\": 750,
    \"currency\": \"KES\",
    \"status\": \"published\",
    \"tag_ids\": [
        16
    ],
