                <h1 id="county-groups">County Groups</h1>

    

                                <h2 id="county-groups-GETapi-groups">List all county groups.</h2>

<p>
</p>

<p>Returns a paginated list of active county groups, ordered by member count.
Supports filtering by county ID and searching by name.</p>

<span id="example-requests-GETapi-groups">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost:8000/api/groups?county_id=1&amp;search=Nairobi&amp;per_page=15" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/groups"
);

const params = {
    "county_id": "1",
    "search": "Nairobi",
    "per_page": "15",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

fetch(url, {
    method: "GET",
    headers,
}).then(response =&gt; response.json());</code></pre></div>

