                                <h2 id="event-tickets-POSTapi-events--event_id--purchase">Purchase Event Tickets</h2>

<p>
</p>

<p>Purchase tickets for a paid event. Supports both authenticated users and guest checkout.
Returns a payment redirect URL for completing the purchase.</p>

<span id="example-requests-POSTapi-events--event_id--purchase">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/events/1/purchase" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"ticket_id\": 1,
    \"quantity\": 2,
    \"phone\": \"+254712345678\",
    \"promo_code\": \"EARLY2024\",
    \"is_waitlist_action\": true,
    \"name\": \"John Doe\",
    \"email\": \"john@example.com\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/events/1/purchase"
);

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "ticket_id": 1,
    "quantity": 2,
    "phone": "+254712345678",
    "promo_code": "EARLY2024",
    "is_waitlist_action": true,
    "name": "John Doe",
    "email": "john@example.com"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

