                                <h2 id="forum-posts-GETapi-forum-threads--thread_slug--posts">List posts for a thread.</h2>

<p>
</p>

<p>Retrieves paginated posts for a specific forum thread.</p>

<span id="example-requests-GETapi-forum-threads--thread_slug--posts">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://localhost:8000/api/forum/threads/welcome-to-the-dadisi-community-hub/posts?per_page=20" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json"</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/forum/threads/welcome-to-the-dadisi-community-hub/posts"
);

const params = {
    "per_page": "20",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Content-Type": "application/json",
    "Accept": "application/json",
};

fetch(url, {
    method: "GET",
    headers,
}).then(response =&gt; response.json());</code></pre></div>

