                    <h2 id="forum-posts-POSTapi-forum-threads--thread_slug--posts">Create a new post.</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Adds a reply to a specific forum thread.
Returns the created post details with user metadata.</p>

<span id="example-requests-POSTapi-forum-threads--thread_slug--posts">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/forum/threads/welcome-to-the-dadisi-community-hub/posts" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"content\": \"architecto\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/forum/threads/welcome-to-the-dadisi-community-hub/posts"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "content": "architecto"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

