                    <h2 id="forum-threads-POSTapi-forum-threads">Create a new thread.</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>



<span id="example-requests-POSTapi-forum-threads">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/forum/threads" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: multipart/form-data" \
    --header "Accept: application/json" \
    --form "category_id=16"\
    --form "county_id=16"\
    --form "tag_ids[]=architecto"\
    --form "title=architecto"\
    --form "content=architecto"\
    --form "media_id=16"\
    --form "image=@C:\Users\pasca\AppData\Local\Temp\php4D57.tmp" </code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/forum/threads"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "multipart/form-data",
    "Accept": "application/json",
};

const body = new FormData();
body.append('category_id', '16');
body.append('county_id', '16');
body.append('tag_ids[]', 'architecto');
body.append('title', 'architecto');
body.append('content', 'architecto');
body.append('media_id', '16');
body.append('image', document.querySelector('input[name="image"]').files[0]);

fetch(url, {
    method: "POST",
    headers,
    body,
}).then(response =&gt; response.json());</code></pre></div>

</span>

<span id="example-responses-POSTapi-forum-threads">
</span>
