);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "title": "architecto",
    "content": "This is the updated description of the thread.",
    "is_pinned": false,
    "is_locked": false,
    "county_id": 16,
    "tag_ids": [
        "architecto"
    ],
    "media_id": 16
};

fetch(url, {
    method: "PUT",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

