                    <h2 id="lab-bookings-POSTapi-bookings--id--cancel">Cancel a booking (POST endpoint).</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Users can cancel their own future bookings.
Returns refund preview information with the cancellation response.
Quota is refunded on cancellation.</p>

<span id="example-requests-POSTapi-bookings--id--cancel">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/bookings/1/cancel" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"cancellation_reason\": \"Schedule conflict\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/bookings/1/cancel"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "cancellation_reason": "Schedule conflict"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

</span>

