                    <h2 id="registrations-POSTapi-admin-events--event_id--registrations-bulk-cancel">Bulk Cancel Registrations (Admin)</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Cancels multiple registrations for a specific event simultaneously.
This method is restricted to administrative staff and handles capacity updates and refund requests.</p>

<span id="example-requests-POSTapi-admin-events--event_id--registrations-bulk-cancel">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://localhost:8000/api/admin/events/1/registrations/bulk/cancel" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"registration_ids\": [
        1,
        2,
        3
    ],
    \"reason\": \"\\\"Event postponed\\\"\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://localhost:8000/api/admin/events/1/registrations/bulk/cancel"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "registration_ids": [
        1,
        2,
        3
    ],
    "reason": "\"Event postponed\""
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

