};

let body = {
    "plan_id": 1,
    "billing_period": "month",
    "phone": "254712345678",
    "payment_method": "pesapal"
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

